/**
 * Ijma Wallet — Splash Screen v2
 *
 * Animation sequence (~4.5s total):
 *   0.0s  Dark background
 *   0.1s  Panel 1 diagonal wipe in (bottom-right corner)
 *   1.0s  Panel 2 wipes over panel 1
 *   1.9s  Panel 3 wipes over — becomes final background
 *   2.1s  Logo materialises with neon ring pings
 *   2.7s  IDENTITY · PAYMENTS · SAVINGS typewriters in
 *   3.4s  Arabic blessing rises
 *   3.7s  Status line pulses
 *   4.2s  Dissolve to app
 *
 * Image fallback:
 *   Expects /images/onboarding-1.jpg, onboarding-2.jpg, onboarding-3.jpg
 *   in public/. If any image 404s the panel shows an Islamic geometric
 *   SVG pattern in the corresponding accent colour.
 */

import { useEffect, useState } from 'react'

// ── Embedded logo ──────────────────────────────────────────────────────────
const LOGO_B64 = 'data:image/webp;base64,'

// ── Palette ─────────────────────────────────────────────────────────────────
const GOLD      = '#C9A84C'
const GOLD_D    = '#8A6F2E'
const GOLD_B    = '#F0D070'
const ORANGE    = '#F7931A'
const WHITE     = '#FAF8F5'
const CYAN      = '#0098D4'
const PURPLE    = '#8B4CF7'
const DARK      = '#0A0A0F'

// Per-panel fallback gradient + geometry colour when images are missing
const PANELS = [
  { grad: 'linear-gradient(160deg,#1A0A00 0%,#6B3A1A 45%,#C9A84C 100%)', geo: GOLD   },
  { grad: 'linear-gradient(160deg,#0A0A1F 0%,#1C1060 45%,#8B4CF7 100%)', geo: PURPLE },
  { grad: 'linear-gradient(160deg,#001A10 0%,#003D1A 45%,#0098D4 100%)', geo: CYAN   },
]

// ── Islamic geometry SVG (used as overlay) ───────────────────────────────────
function IslamicGeometry({ color, strength }) {
  const o = strength || 0.18
  return (
    <svg
      style={{ position:'absolute', inset:0, width:'100%', height:'100%', pointerEvents:'none' }}
      xmlns="http://www.w3.org/2000/svg"
    >
      <defs>
        <pattern id={`geo-${color.slice(1)}`} x="0" y="0" width="120" height="104" patternUnits="userSpaceOnUse">
          <polygon points="60,4 116,32 116,88 60,116 4,88 4,32"
            fill="none" stroke={color} strokeWidth="0.9" opacity={o * 6} />
          <polygon points="60,18 102,40 102,84 60,106 18,84 18,40"
            fill="none" stroke={color} strokeWidth="0.6" opacity={o * 4} />
          <polygon points="60,32 88,48 88,80 60,96 32,80 32,48"
            fill="none" stroke={color} strokeWidth="0.4" opacity={o * 3} />
          <line x1="60" y1="4"  x2="60"  y2="116" stroke={color} strokeWidth="0.3" opacity={o * 2} />
          <line x1="4"  y1="60" x2="116" y2="60"  stroke={color} strokeWidth="0.3" opacity={o * 2} />
          <line x1="4"  y1="32" x2="116" y2="88"  stroke={color} strokeWidth="0.2" opacity={o} />
          <line x1="4"  y1="88" x2="116" y2="32"  stroke={color} strokeWidth="0.2" opacity={o} />
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill={`url(#geo-${color.slice(1)})`} />
    </svg>
  )
}

// ── Single diagonal-wipe panel ───────────────────────────────────────────────
function DiagonalPanel({ src, grad, geo, show }) {
  const [imgOk,  setImgOk]  = useState(false)
  const [imgErr, setImgErr] = useState(false)

  // clip-path: diagonal wipe from bottom-right corner
  // closed = all four points collapsed to bottom-right
  // open   = full rectangle
  const clip = show
    ? 'polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%)'
    : 'polygon(100% 100%, 100% 100%, 100% 100%, 100% 100%)'

  return (
    <div style={{
      position: 'absolute', inset: 0, overflow: 'hidden',
      clipPath: clip,
      transition: 'clip-path 0.88s cubic-bezier(0.77,0,0.175,1)',
    }}>
      {/* Background: image if available, gradient fallback otherwise */}
      { (!imgErr) &&
        <img
          src={src}
          onLoad={ () => setImgOk(true) }
          onError={ () => setImgErr(true) }
          style={{
            position:'absolute', inset:0,
            width:'100%', height:'100%',
            objectFit:'cover', objectPosition:'center top',
            opacity: imgOk ? 1 : 0,
            transition: 'opacity 0.3s',
          }}
          alt=""
        />
      }
      { (imgErr || !imgOk) &&
        <div style={{ position:'absolute', inset:0, background: grad }} />
      }

      {/* Islamic geometry overlay — subtle on photos, vivid on gradient */}
      <IslamicGeometry color={geo} strength={imgErr ? 0.22 : 0.06} />

      {/* Cinematic dark vignette */}
      <div style={{
        position:'absolute', inset:0,
        background:'radial-gradient(ellipse at 50% 40%, transparent 25%, rgba(0,0,0,0.55) 100%)',
      }} />

      {/* Bottom darkening for text contrast */}
      <div style={{
        position:'absolute', inset:0,
        background:'linear-gradient(to bottom, rgba(0,0,0,0) 40%, rgba(0,0,0,0.72) 100%)',
      }} />
    </div>
  )
}

// ── Main SplashScreen ────────────────────────────────────────────────────────
export default function SplashScreen({ onComplete }) {
  const [show1,  setShow1]  = useState(false)
  const [show2,  setShow2]  = useState(false)
  const [show3,  setShow3]  = useState(false)
  const [logoOn, setLogoOn] = useState(false)
  const [rings,  setRings]  = useState(false)
  const [glow,   setGlow]   = useState(false)
  const [txtPh,  setTxtPh]  = useState(0)       // 0=hidden 1=typewriting 2=done
  const [typed,  setTyped]  = useState({ identity:'', payments:'', savings:'' })
  const [bless,  setBless]  = useState(false)
  const [status, setStatus] = useState('')
  const [fade,   setFade]   = useState(false)

  useEffect(() => {
    const timers = []
    const t = (ms, fn) => { timers.push(setTimeout(fn, ms)) }

    t( 80,  () => setShow1(true))
    t( 960, () => setShow2(true))
    t(1840, () => setShow3(true))
    t(2050, () => { setLogoOn(true) })
    t(2220, () => setRings(true))
    t(2580, () => setGlow(true))
    t(2750, () => {
      setTxtPh(1)
      tw('identity', 'IDENTITY', 58, timers, 0)
      tw('payments', 'PAYMENTS', 52, timers, 530)
      tw('savings',  'SAVINGS',  52, timers, 1020)
    })
    t(3800, () => setBless(true))
    t(3980, () => {
      setStatus('Initialising secure enclave')
      timers.push(setTimeout(() => setStatus('Loading keys'), 280))
      timers.push(setTimeout(() => setStatus('Ready'),        620))
    })
    t(4700, () => setFade(true))
    t(5200, () => onComplete?.())

    return () => timers.forEach(clearTimeout)
  }, [])

  function tw(key, text, interval, timers, offset) {
    text.split('').forEach((ch, i) => {
      timers.push(setTimeout(() => {
        setTyped(prev => ({ ...prev, [key]: prev[key] + ch }))
      }, offset + i * interval))
    })
  }

  return (
    <div style={{
      position:'fixed', inset:0, zIndex:9999,
      background: DARK, overflow:'hidden',
      opacity: fade ? 0 : 1,
      transition: fade ? 'opacity 0.55s ease-in' : 'none',
    }}>

      {/* ── Diagonal panels (back → front) ───────────────────────────── */}
      <DiagonalPanel src={import.meta.env.BASE_URL + "images/onboarding-1.jpg"} grad={PANELS[0].grad} geo={PANELS[0].geo} show={show1} />
      <DiagonalPanel src={import.meta.env.BASE_URL + "images/onboarding-2.jpg"} grad={PANELS[1].grad} geo={PANELS[1].geo} show={show2} />
      <DiagonalPanel src={import.meta.env.BASE_URL + "images/onboarding-3.jpg"} grad={PANELS[2].grad} geo={PANELS[2].geo} show={show3} />

      {/* ── Foreground content ────────────────────────────────────────── */}
      <div style={{
        position:'absolute', inset:0, zIndex:10,
        display:'flex', flexDirection:'column',
        alignItems:'center', justifyContent:'center',
      }}>

        {/* Logo + rings */}
        <div style={{
          position:'relative',
          width:'min(200px,52vw)', height:'min(200px,52vw)',
          display:'flex', alignItems:'center', justifyContent:'center',
          marginBottom: 28,
        }}>
          { rings && <>
            <div style={{ position:'absolute', width:'140%', height:'140%', borderRadius:'50%',
              border:`1.5px solid ${GOLD}`, animation:'rp 1.4s ease-out forwards' }} />
            <div style={{ position:'absolute', width:'140%', height:'140%', borderRadius:'50%',
              border:`1px solid ${GOLD}66`, animation:'rp 1.4s 0.18s ease-out forwards' }} />
            <div style={{ position:'absolute', width:'140%', height:'140%', borderRadius:'50%',
              border:`0.5px solid ${GOLD}33`, animation:'rp 1.4s 0.36s ease-out forwards' }} />
          </> }

          { glow &&
            <div style={{
              position:'absolute', width:'125%', height:'125%', borderRadius:'50%',
              background:`radial-gradient(ellipse, ${GOLD}2A 0%, transparent 70%)`,
              animation:'gp 2.5s ease-in-out infinite',
            }} />
          }

          <img src={LOGO_B64} alt="Ijma Wallet" style={{
            width:'100%', height:'100%', objectFit:'contain',
            opacity: logoOn ? 1 : 0,
            transform: logoOn ? 'scale(1)' : 'scale(0.8)',
            filter: glow
              ? `drop-shadow(0 0 28px ${GOLD}AA) drop-shadow(0 0 10px ${GOLD_B}) drop-shadow(0 0 56px ${GOLD}44)`
              : `drop-shadow(0 0 6px ${GOLD}66)`,
            transition: logoOn
              ? 'opacity 0.7s ease-out, transform 0.7s cubic-bezier(0.175,0.885,0.32,1.275), filter 1s ease'
              : 'none',
          }} />
        </div>

        {/* Tagline */}
        <div style={{
          display:'flex', gap:8, alignItems:'center',
          fontFamily:"'JetBrains Mono','Courier New',monospace",
          fontSize:'clamp(10px,2.8vw,13px)', fontWeight:700, letterSpacing:'0.2em',
          marginBottom: 18,
          opacity: txtPh >= 1 ? 1 : 0, transition:'opacity 0.3s',
          minHeight: 20,
        }}>
          <span style={{ color: WHITE }}>{typed.identity}</span>
          { typed.identity === 'IDENTITY' && <span style={{ color:GOLD, opacity:0.7 }}>·</span> }
          <span style={{ color: CYAN }}>{typed.payments}</span>
          { typed.payments === 'PAYMENTS' && <span style={{ color:GOLD, opacity:0.7 }}>·</span> }
          <span style={{ color: PURPLE }}>{typed.savings}</span>
        </div>

        {/* Arabic blessing */}
        <div style={{
          fontFamily:"'Amiri','Scheherazade New','Arial',serif",
          fontSize:'clamp(13px,3.5vw,17px)',
          color: GOLD, direction:'rtl', letterSpacing:'0.05em',
          marginBottom: 20,
          opacity: bless ? 0.88 : 0,
          transform: bless ? 'translateY(0)' : 'translateY(10px)',
          transition:'opacity 0.9s ease, transform 0.9s ease',
          textShadow:`0 0 24px ${GOLD}77`,
        }}>
          بسم الله الرحمن الرحيم
        </div>

        {/* Status line */}
        <div style={{
          fontFamily:"'JetBrains Mono','Courier New',monospace",
          fontSize:10, color: GOLD_D, letterSpacing:'0.12em',
          opacity: status ? 1 : 0, transition:'opacity 0.3s',
          display:'flex', alignItems:'center', gap:6,
        }}>
          <span style={{
            display:'inline-block', width:6, height:6, borderRadius:3,
            background: status === 'Ready' ? '#00A86B' : GOLD,
            animation: status !== 'Ready' ? 'blink 0.8s step-end infinite' : 'none',
            boxShadow: status === 'Ready' ? '0 0 8px #00A86B' : `0 0 6px ${GOLD}`,
          }} />
          {status}
          { status && status !== 'Ready' &&
            <span style={{ animation:'blink 0.8s step-end infinite' }}>_</span>
          }
        </div>
      </div>

      <style>{`
        @keyframes rp {
          from { transform:scale(1);   opacity:0.95; }
          to   { transform:scale(1.85); opacity:0; }
        }
        @keyframes gp {
          0%,100% { opacity:0.5;  transform:scale(1);    }
          50%     { opacity:1;    transform:scale(1.06); }
        }
        @keyframes blink {
          0%,100% { opacity:1; }
          50%     { opacity:0; }
        }
      `}</style>
    </div>
  )
}
